#include<bits/stdc++.h>
using namespace std;
        int dp[502][502][301]={0};
//bool v[502][502];
int main(){
    int t;
    cin>>t;
    while(t--){
        int n,m,x;
        char a;
        memset(dp,0,sizeof(dp));
        //memset(v,0,sizeof(v));
        cin>>n>>m>>x;
        for(int i=1;i<=n;i++){
            for(int j=1;j<=m;j++){
                cin>>a;
                for(int k=0;k<=x;k++){
                    if(a=='1'){
                        dp[i][j][k]=max(dp[i][j][k],max(dp[i-1][j][k],dp[i][j-1][k])+1);
                    }
                    dp[i][j][k]=max(dp[i][j][k],max(dp[i-1][j][k],dp[i][j-1][k]));
                    if(k>0&&a=='?'){
                        //a='1';
                        dp[i][j][k]=max(dp[i][j][k],max(dp[i-1][j][k-1],dp[i][j-1][k-1])+1);
                    }

                }
            }
        }
        int mx=0;
        for(int k=0; k<=x; k++) mx=max(mx,dp[n][m][k]);
        cout<<mx<<"\n";
    }
    return 0;
}
